option.value:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: Arial, Helvetica, sans-serif;
  background: #0f172a;
  color: #e5e7eb;
  line-height: 1.6;
}

.nav {
  position: sticky;
  top: 0;
  z-index: 10;
  background: rgba(15, 23, 42, 0.95);
  border-bottom: 1px solid #1e293b;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 18px 12%;
}

.logo {
  color: #60a5fa;
  font-weight: 800;
  font-size: 22px;
}

.nav a {
  color: #cbd5e1;
  text-decoration: none;
  margin-left: 22px;
  font-size: 14px;
  transition: color 0.2s ease;
}

.nav a:hover {
  color: #60a5fa;
}

.nav a.active {
  color: #60a5fa;
}

.hero {
  text-align: center;
  padding: 105px 12% 90px;
  background:
    linear-gradient(rgba(15, 23, 42, 0.92), rgba(15, 23, 42, 0.98)),
    radial-gradient(circle at top, #1d4ed8 0%, transparent 35%);
}

.eyebrow {
  color: #60a5fa;
  font-weight: 700;
  letter-spacing: 2px;
  margin-bottom: 18px;
}

.hero h1 {
  font-size: clamp(44px, 7vw, 82px);
  text-transform: uppercase;
  letter-spacing: 4px;
  line-height: 1;
}

.hero h2 {
  color: #93c5fd;
  margin-top: 18px;
  font-size: 24px;
}

.hero-text {
  max-width: 780px;
  margin: 24px auto;
  color: #cbd5e1;
  font-size: 18px;
}

.hero-proof {
  margin-top: 14px;
  color: #93c5fd;
  font-size: 14px;
  letter-spacing: 0.2px;
}

#dynamic-role {
  color: #bfdbfe;
  border-right: 2px solid #60a5fa;
  padding-right: 6px;
}

.buttons {
  margin-top: 30px;
}

.btn {
  display: inline-block;
  padding: 12px 20px;
  border: 1px solid #334155;
  border-radius: 10px;
  color: #e5e7eb;
  text-decoration: none;
  margin: 8px;
  transition: 0.2s ease;
}

.btn:hover {
  transform: translateY(-2px);
  border-color: #60a5fa;
}

.btn.primary {
  background: #2563eb;
  border-color: #2563eb;
}

.stats {
  margin: 42px auto 0;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 14px;
  max-width: 880px;
}

.stat-card {
  position: relative;
  overflow: hidden;
  background: rgba(30, 41, 59, 0.85);
  border: 1px solid #334155;
  border-radius: 12px;
  padding: 16px 14px;
  box-shadow:
    0 10px 24px rgba(0, 0, 0, 0.2),
    inset 0 1px 0 rgba(148, 163, 184, 0.12);
  transition: transform 0.2s ease, border-color 0.2s ease;
}

.stat-card:hover {
  transform: translateY(-4px);
  border-color: #3b82f6;
}

.stat-number {
  color: #93c5fd;
  font-size: 36px;
  font-weight: 700;
  line-height: 1;
}

.stat-label {
  margin-top: 8px;
  color: #cbd5e1;
  font-size: 13px;
}

.section {
  padding: 75px 12%;
  max-width: 1200px;
  margin: auto;
}

.section h2 {
  text-align: center;
  font-size: 32px;
  margin-bottom: 18px;
}

.section > p {
  max-width: 900px;
  margin: 0 auto;
  text-align: center;
  color: #cbd5e1;
  font-size: 17px;
}

.grid,
.project-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 22px;
  margin-top: 38px;
}

.card,
.project-card,
.timeline-item {
  position: relative;
  overflow: hidden;
  background:
    linear-gradient(165deg, rgba(59, 130, 246, 0.08), transparent 35%),
    #1e293b;
  border: 1px solid #2d3e57;
  border-radius: 16px;
  padding: 24px;
  box-shadow:
    0 12px 30px rgba(0, 0, 0, 0.25),
    inset 0 1px 0 rgba(148, 163, 184, 0.12);
  transform: translateY(0) scale(1);
  transition: transform 0.25s ease, box-shadow 0.25s ease, border-color 0.25s ease;
}

.card::before,
.project-card::before,
.timeline-item::before {
  content: "";
  position: absolute;
  inset: -40% 40% auto -40%;
  height: 130px;
  background: radial-gradient(circle, rgba(96, 165, 250, 0.18), transparent 65%);
  opacity: 0;
  transition: opacity 0.3s ease;
  pointer-events: none;
}

.card::after,
.project-card::after,
.timeline-item::after {
  content: "";
  position: absolute;
  top: 0;
  left: 20px;
  right: 20px;
  height: 2px;
  background: linear-gradient(90deg, transparent, #60a5fa, transparent);
  opacity: 0.5;
}

.card:hover,
.project-card:hover,
.timeline-item:hover {
  transform: translateY(-6px) scale(1.01);
  border-color: #3b82f6;
  box-shadow:
    0 20px 42px rgba(0, 0, 0, 0.35),
    0 0 0 1px rgba(96, 165, 250, 0.2);
}

.card:hover::before,
.project-card:hover::before,
.timeline-item:hover::before {
  opacity: 1;
}

.card h3,
.project-card h3,
.timeline-item h3 {
  color: #f8fafc;
  margin-bottom: 12px;
}

.card-icon {
  font-size: 42px;
  line-height: 1;
  margin-bottom: 16px;
  text-align: center;
  filter: drop-shadow(0 6px 18px rgba(59, 130, 246, 0.28));
}

.card {
  text-align: center;
}

.card p,
.project-card p,
.timeline-item p {
  color: #cbd5e1;
}

.timeline-item ul {
  margin-left: 18px;
  color: #cbd5e1;
}

.timeline-item li {
  margin-bottom: 6px;
}

.project-card {
  min-height: 240px;
}

.project-head {
  display: flex;
  justify-content: space-between;
  gap: 10px;
}

.project-head a {
  color: #93c5fd;
  text-decoration: none;
  font-size: 13px;
  border: 1px solid #334155;
  border-radius: 999px;
  padding: 4px 10px;
  height: fit-content;
}

.project-head a:hover {
  color: #dbeafe;
  border-color: #60a5fa;
}

.project-points {
  margin: 14px 0 0 18px;
  color: #cbd5e1;
}

.project-points li {
  margin-bottom: 4px;
  font-size: 14px;
}

.project-card.hidden {
  display: none;
}

.project-filters {
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 28px;
}

.filter-btn {
  background: #0f172a;
  border: 1px solid #334155;
  color: #cbd5e1;
  border-radius: 999px;
  padding: 8px 14px;
  cursor: pointer;
  transition: all 0.2s ease;
}

.filter-btn:hover,
.filter-btn.active {
  border-color: #60a5fa;
  color: #bfdbfe;
}

.tags {
  margin-top: 18px;
}

.cert-grid {
  margin-top: 28px;
}

.cert-card {
  min-height: 220px;
}

.cert-org {
  color: #93c5fd;
  font-size: 14px;
  margin-bottom: 8px;
}

.cert-link {
  display: inline-block;
  margin-top: 14px;
  color: #93c5fd;
  text-decoration: none;
  border-bottom: 1px solid transparent;
}

.cert-link:hover {
  border-bottom-color: #93c5fd;
}

.tags span {
  display: inline-block;
  background: #0f172a;
  color: #93c5fd;
  border: 1px solid #334155;
  padding: 5px 9px;
  border-radius: 8px;
  font-size: 12px;
  margin: 4px;
}

.timeline-item {
  margin: 24px auto;
  max-width: 900px;
  border-left: 4px solid #2563eb;
}

.contact {
  text-align: center;
}

.reveal {
  opacity: 0;
  transform: translateY(18px);
  transition: opacity 0.5s ease, transform 0.5s ease;
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

footer {
  text-align: center;
  padding: 35px;
  border-top: 1px solid #1e293b;
  color: #94a3b8;
}

.back-to-top {
  position: fixed;
  right: 20px;
  bottom: 20px;
  width: 42px;
  height: 42px;
  border-radius: 50%;
  border: 1px solid #334155;
  background: #1e293b;
  color: #e5e7eb;
  cursor: pointer;
  opacity: 0;
  pointer-events: none;
  transform: translateY(10px);
  transition: opacity 0.2s ease, transform 0.2s ease;
}

.back-to-top.visible {
  opacity: 1;
  pointer-events: auto;
  transform: translateY(0);
}

@media (prefers-reduced-motion: reduce) {
  .card,
  .project-card,
  .timeline-item,
  .stat-card {
    transition: none;
  }

  .card:hover,
  .project-card:hover,
  .timeline-item:hover,
  .stat-card:hover {
    transform: none;
  }
}

@media (max-width: 900px) {
  .grid,
  .project-grid {
    grid-template-columns: 1fr;
  }

  .project-head {
    align-items: center;
  }

  .stats {
    grid-template-columns: 1fr;
  }

  .nav {
    flex-direction: column;
    gap: 12px;
  }

  .nav a {
    margin: 0 8px;
  }
}

